import{_ as o,o as t,c as a,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Liveview","description":"","frontmatter":{"title":"Liveview","slug":"liveview"},"headers":[],"relativePath":"account-hub/liveview.md","filePath":"account-hub/liveview.md"}'),n={name:"account-hub/liveview.md"};function s(r,e,d,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> for Liveview, which is slated for deprecation.</p><p>In the <a href="./liveview-new.html">new version of Branch</a>, attribution windows are configured under <strong>Testing &amp; Monitoring</strong> → <strong>Liveview</strong>.</p></div><h2 id="supported-objects" tabindex="-1">Supported objects <a class="header-anchor" href="#supported-objects" aria-label="Permalink to &quot;Supported objects&quot;">​</a></h2><p>Liveview enables you to debug the following objects:</p><ol><li>Events</li><li>Webhook records</li></ol><p><code>Events</code> and <code>Webhook records</code> allow advanced filtering on a number of dimensions, including per-event and per-device dimensions not surfaced elsewhere on the Dashboard. Access to this data is determined by the <a href="./add-manage-users-roles-permissions-access.html#access-levels">Sensitive Data access level</a>.</p><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><h3 id="_1-choose-an-object" tabindex="-1">1. Choose an object <a class="header-anchor" href="#_1-choose-an-object" aria-label="Permalink to &quot;1. Choose an object&quot;">​</a></h3><p>Choose among the supported objects using the tabs at the top of the screen.</p><h3 id="_2-choose-event-type" tabindex="-1">2. Choose event type <a class="header-anchor" href="#_2-choose-event-type" aria-label="Permalink to &quot;2. Choose event type&quot;">​</a></h3><p>If you are viewing <code>Events</code>, then be sure to choose the appropriate event type from the dropdown, e.g. <code>commerce event</code>.</p><h3 id="_3-add-advanced-filters-optional" tabindex="-1">3. Add advanced filters (optional) <a class="header-anchor" href="#_3-add-advanced-filters-optional" aria-label="Permalink to &quot;3. Add advanced filters (optional)&quot;">​</a></h3><p>Add advanced filters. Some of the most useful include <code>name</code> (e.g. <code>PURCHASE</code>), <code>feature</code>, <code>channel</code>, <code>campaign</code>, and device identifiers like <code>IDFA</code>.</p><div class="info custom-block"><p class="custom-block-title">What does it mean if the OS is &quot;Robots&quot; in Liveview reports?</p><p>This means that one of these conditions are true:</p><ol><li>The link clicks are not from a true iOS, Android, or other platform user agent</li><li>The link clicks are from a bot like a Google scraper</li></ol></div><h3 id="_4-viewing-webhook-records" tabindex="-1">4. Viewing Webhook Records <a class="header-anchor" href="#_4-viewing-webhook-records" aria-label="Permalink to &quot;4. Viewing Webhook Records&quot;">​</a></h3><p>To see the webhook request and response for debugging, you can use the webhook records tab. This allows you to see what information is getting sent and whether it was successful (200 status code) or not (400 or 500 status code)</p><div class="warning custom-block"><p class="custom-block-title">If you are trying to view Webhook Records going to a Data Integration</p><p>You will need to filter by webhook_partner_key and specify the value in the format di_partner_name. For example, Adobe Analytics Processing Rules is di_adobe_analytics_pr, Mixpanel is di_mixpanel, etc... If you don&#39;t add this filter the webhook records for those DIs will not show.</p></div><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Why is my link showing the same campaign name even though I’m sending dynamic values via query parameters?</summary><p>We do not allow you to override default values set for analytics parameters (&#39;~channel&#39;, &#39;~tags&#39;,&#39;~campaign&#39;, &#39;~feature&#39;) at the link level via query parameters. This is done to prevent spam.</p></details><details><summary>Why am I able to see revenue data on Liveview but not on the analytics page?</summary><p>Revenue data will only populate for <code>PURCHASE</code> events. The event must be a standard Branch Commerce Event with the type <code>PURCHASE</code>, as outlined in the Commerce table in this <a href="./track-branch-events.html#track-commerce-events">section</a>.</p><p>If you use a different type of event other than a <code>PURCHASE</code> event, you will only see the data in Liveview, and the same data will not populate the Dashboard.</p><p>For more information, please refer to our documentation on <a href="./track-branch-events.html">Tracking Commerce, Content, Lifecycle and Custom Events</a>.</p></details>',19)])])}const m=o(n,[["render",s]]);export{u as __pageData,m as default};
